export type FieldKey =
  | "water_extent_status"
  | "flood_risk"
  | "water_clarity"
  | "shoreline_encroachment"
  | "agriculture_present"
  | "crop_stress_level"
  | "crop_stress_type"
  | "cultivation_expanding_toward_water"
  | "settlement_visible"
  | "bare_soil_expansion";

export type Zone = "core" | "buffer";

export interface FieldRow {
  field: FieldKey;
  label: string;
  zone: Zone;
  /** Valid values for this field (categorical) — shown as captions. */
  valid: string;
  claude: number;
  base: number;
  finetuned: number;
}

