/** Number to a percentage string, no decimals. */
export const pct = (x: number): string => `${(x * 100).toFixed(0)}%`;
/** As percentage points (for deltas), one decimal. */
export const pp = (x: number): string => `${(x * 100).toFixed(1)}`;
